package ru.memearena.tournament.application; import org.springframework.data.domain.*; import org.springframework.http.*; import org.springframework.stereotype.*; import ru.memearena.error.*; import ru.memearena.meme.domain.*; import ru.memearena.meme.infrastructure.*; import ru.memearena.tournament.api.TournamentDtos.*; import ru.memearena.tournament.domain.*; import ru.memearena.tournament.infrastructure.*; import java.util.*; import java.util.function.*; import java.util.stream.*;
@Service public class TournamentQueryService{ private final TournamentRepository tournaments; private final TournamentMatchRepository matches; private final TournamentVoteRepository votes; private final MemeRepository memes; public TournamentQueryService(TournamentRepository t,TournamentMatchRepository m,TournamentVoteRepository v,MemeRepository memes){this.tournaments=t;this.matches=m;this.votes=v;this.memes=memes;} public TournamentDto current(Optional<UUID> user){return tournaments.findFirstByOrderByTournamentDateDesc().map(t->dto(t,user,true)).orElse(null);} public TournamentDto byId(UUID id,Optional<UUID> user){return dto(tournaments.findById(id).orElseThrow(()->new ApiException(HttpStatus.NOT_FOUND,ErrorCode.TOURNAMENT_NOT_FOUND,"Tournament not found")),user,false);} public Page<HistoryItem> history(Pageable p){return tournaments.findAllByOrderByTournamentDateDesc(p).map(t->{Meme w=t.winnerMemeId==null?null:memes.findById(t.winnerMemeId).orElse(null);return new HistoryItem(t.id,t.tournamentDate,t.status.name(),ru.memearena.tournament.api.TournamentDtos.meme(w));});} private TournamentDto dto(Tournament t,Optional<UUID> user,boolean currentOnly){List<TournamentMatch> ms=currentOnly?matches.findByTournamentIdAndRoundNumberOrderByMatchNumber(t.id,t.currentRound):matches.findByTournamentIdOrderByRoundNumberAscMatchNumberAsc(t.id); Set<UUID> ids=ms.stream().flatMap(m->Stream.of(m.leftMemeId,m.rightMemeId,m.winnerMemeId)).filter(Objects::nonNull).collect(Collectors.toSet()); if(t.winnerMemeId!=null)ids.add(t.winnerMemeId); Map<UUID,Meme> mm=memes.findAllByIds(ids).stream().collect(Collectors.toMap(Meme::getId,Function.identity())); List<MatchDto> list=ms.stream().map(m->{UUID sel=user.flatMap(u->votes.findByMatchIdAndUserId(m.id,u)).map(v->v.selectedMemeId).orElse(null); boolean show=m.status!=TournamentMatchStatus.ACTIVE||sel!=null; return new MatchDto(m.id,m.roundNumber,m.matchNumber,m.status.name(),ru.memearena.tournament.api.TournamentDtos.meme(mm.get(m.leftMemeId)),ru.memearena.tournament.api.TournamentDtos.meme(mm.get(m.rightMemeId)),show?m.leftVotes:null,show?m.rightVotes:null,sel,m.winnerMemeId,m.startsAt,m.endsAt);}).toList(); return new TournamentDto(t.id,t.tournamentDate,t.status.name(),t.currentRound,t.startsAt,list,ru.memearena.tournament.api.TournamentDtos.meme(mm.get(t.winnerMemeId)));} }
